const ALL_Q = { sleep: SLEEP_Q, adults: ADULTS_Q };

function genCode(p='HZ') {
  return `${p}-${Math.random().toString(36).substring(2,6).toUpperCase()}-${Math.random().toString(36).substring(2,6).toUpperCase()}`;
}

function getQuestions(mode) {
  const q = ALL_Q[mode] || ADULTS_Q;
  return [...q].sort(() => Math.random() - 0.5);
}

function findQuestion(id) {
  for (const bank of Object.values(ALL_Q)) {
    const q = bank.find(q => q.id === id);
    if (q) return q;
  }
  return null;
}

exports.handler = async (event) => {
  const h = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'Content-Type',
    'Content-Type': 'application/json'
  };
  if (event.httpMethod === 'OPTIONS') return { statusCode: 200, headers: h, body: '' };

  try {
    const body = JSON.parse(event.body || '{}');
    const { action } = body;

    // ===== VALIDATE CODE =====
    if (action === 'validateCode') {
      const { code } = body;
      if (!code) return R(400, { error: 'كود مطلوب' }, h);
      const data = await redis('GET', `hazal:code:${code.toUpperCase()}`);
      if (!data) return R(200, { valid: false, error: 'الكود غير موجود أو منتهي الصلاحية' }, h);
      const parsed = JSON.parse(data);
      if (parsed.expiresAt && Date.now() > parsed.expiresAt)
        return R(200, { valid: false, error: 'انتهت صلاحية الكود' }, h);
      return R(200, { valid: true, plan: parsed.plan || 'basic' }, h);
    }

    // ===== CREATE ROOM =====
    if (action === 'createRoom') {
      const { playerName, mode } = body;
      if (!playerName || !mode) return R(400, { error: 'بيانات ناقصة' }, h);
      const roomCode = genCode('HZ');
      const playerId = genCode('P');
      const questions = getQuestions(mode);
      const room = {
        code: roomCode, mode, host: playerId,
        players: [{ id: playerId, name: playerName, score: 0 }],
        questions: questions.map(q => q.id),
        status: 'waiting',
        currentQ: 0,
        phase: 'waiting', // waiting | question | reveal
        answers: {},
        createdAt: Date.now()
      };
      await redis('SET', `hazal:room:${roomCode}`, JSON.stringify(room));
      await redis('EXPIRE', `hazal:room:${roomCode}`, 86400);
      await redis('SET', `hazal:chat:${roomCode}`, JSON.stringify([]));
      await redis('EXPIRE', `hazal:chat:${roomCode}`, 86400);
      return R(200, { roomCode, playerId, room }, h);
    }

    // ===== JOIN ROOM =====
    if (action === 'joinRoom') {
      const { roomCode, playerName } = body;
      if (!roomCode || !playerName) return R(400, { error: 'بيانات ناقصة' }, h);
      const raw = await redis('GET', `hazal:room:${roomCode.toUpperCase()}`);
      if (!raw) return R(404, { error: 'الغرفة غير موجودة' }, h);
      const room = JSON.parse(raw);
      if (room.players.length >= 5) return R(400, { error: 'الغرفة ممتلئة (٥ لاعبين كحد أقصى)' }, h);
      const playerId = genCode('P');
      room.players.push({ id: playerId, name: playerName, score: 0 });
      await redis('SET', `hazal:room:${roomCode.toUpperCase()}`, JSON.stringify(room));
      // System chat msg
      const chatRaw = await redis('GET', `hazal:chat:${roomCode.toUpperCase()}`);
      const chat = chatRaw ? JSON.parse(chatRaw) : [];
      chat.push({ id: Date.now(), type: 'system', text: `${playerName} انضم للغرفة! 🎉 هزّول يرحب بك 🤖`, ts: Date.now() });
      await redis('SET', `hazal:chat:${roomCode.toUpperCase()}`, JSON.stringify(chat));
      return R(200, { playerId, room }, h);
    }

    // ===== GET ROOM =====
    if (action === 'getRoom') {
      const { roomCode } = body;
      const raw = await redis('GET', `hazal:room:${roomCode.toUpperCase()}`);
      if (!raw) return R(404, { error: 'الغرفة غير موجودة' }, h);
      return R(200, { room: JSON.parse(raw) }, h);
    }

    // ===== GET QUESTION =====
    if (action === 'getQuestion') {
      const { roomCode } = body;
      const raw = await redis('GET', `hazal:room:${roomCode.toUpperCase()}`);
      if (!raw) return R(404, { error: 'الغرفة غير موجودة' }, h);
      const room = JSON.parse(raw);
      if (room.phase === 'done' || room.currentQ >= room.questions.length || room.currentQ >= 20) {
        return R(200, { done: true }, h);
      }
      const q = room.currentQuestion || findQuestion(room.questions[room.currentQ]);
      if (!q) return R(200, { done: true }, h);
      const intro = HAZZOUL_INTROS[Math.floor(Math.random() * HAZZOUL_INTROS.length)];
      return R(200, { question: q, intro, phase: room.phase, currentQ: room.currentQ }, h);
    }

    // ===== START GAME =====
    if (action === 'startGame') {
      const { roomCode, playerId } = body;
      const raw = await redis('GET', `hazal:room:${roomCode.toUpperCase()}`);
      if (!raw) return R(404, { error: 'الغرفة غير موجودة' }, h);
      const room = JSON.parse(raw);
      if (room.host !== playerId) return R(403, { error: 'فقط المضيف يقدر يبدأ' }, h);
      room.status = 'playing';
      room.phase = 'question';
      room.currentQ = 0;
      room.answers = {};
      const q = findQuestion(room.questions[0]);
      room.currentQuestion = q;
      await redis('SET', `hazal:room:${roomCode.toUpperCase()}`, JSON.stringify(room));
      // Announce in chat
      const chatRaw = await redis('GET', `hazal:chat:${roomCode.toUpperCase()}`);
      const chat = chatRaw ? JSON.parse(chatRaw) : [];
      chat.push({ id: Date.now(), type: 'bot', text: `${HAZZOUL_INTROS[Math.floor(Math.random() * HAZZOUL_INTROS.length)]} 🎮 اللعبة بدأت!`, ts: Date.now() });
      await redis('SET', `hazal:chat:${roomCode.toUpperCase()}`, JSON.stringify(chat));
      return R(200, { ok: true }, h);
    }

    // ===== SUBMIT ANSWER (synchronized) =====
    if (action === 'submitAnswer') {
      const { roomCode, playerId, playerName, answerIndex } = body;
      const raw = await redis('GET', `hazal:room:${roomCode.toUpperCase()}`);
      if (!raw) return R(404, { error: 'الغرفة غير موجودة' }, h);
      const room = JSON.parse(raw);

      if (room.phase !== 'question') return R(200, { ok: true, alreadyRevealed: true }, h);

      const q = room.currentQuestion || findQuestion(room.questions[room.currentQ]);
      const answerText = q?.options?.[answerIndex] || '?';
      const botResp = q?.bot?.[String(answerIndex)] || HAZZOUL_CHAT[Math.floor(Math.random() * HAZZOUL_CHAT.length)];

      room.answers[playerId] = {
        playerName, answerIndex, answerText, botResp
      };

      // Update score
      const pi = room.players.findIndex(p => p.id === playerId);
      if (pi >= 0) room.players[pi].score = (room.players[pi].score || 0) + 10;

      // Check if ALL players answered → auto reveal
      const answeredCount = Object.keys(room.answers).length;
      const totalPlayers = room.players.length;

      if (answeredCount >= totalPlayers) {
        room.phase = 'reveal';
        // Post all answers to chat
        const chatRaw = await redis('GET', `hazal:chat:${roomCode.toUpperCase()}`);
        const chat = chatRaw ? JSON.parse(chatRaw) : [];
        chat.push({ id: Date.now(), type: 'bot', text: REVEAL_INTROS[Math.floor(Math.random() * REVEAL_INTROS.length)], ts: Date.now() });
        Object.entries(room.answers).forEach(([pid, ans], idx) => {
          chat.push({ id: Date.now() + idx + 1, type: 'answer', playerId: pid, playerName: ans.playerName, answer: ans.answerText, questionText: q?.text || '', ts: Date.now() + idx + 1 });
          chat.push({ id: Date.now() + idx + 100, type: 'bot', text: `${ans.playerName}: ${ans.botResp}`, ts: Date.now() + idx + 100 });
        });
        await redis('SET', `hazal:chat:${roomCode.toUpperCase()}`, JSON.stringify(chat.slice(-100)));
      }

      await redis('SET', `hazal:room:${roomCode.toUpperCase()}`, JSON.stringify(room));
      return R(200, { ok: true, phase: room.phase, answeredCount, totalPlayers }, h);
    }

    // ===== REVEAL (host forces reveal after timer) =====
    if (action === 'revealAnswers') {
      const { roomCode, playerId } = body;
      const raw = await redis('GET', `hazal:room:${roomCode.toUpperCase()}`);
      if (!raw) return R(404, { error: 'الغرفة غير موجودة' }, h);
      const room = JSON.parse(raw);
      if (room.host !== playerId) return R(403, { error: 'فقط المضيف' }, h);
      if (room.phase === 'reveal') return R(200, { ok: true }, h);

      room.phase = 'reveal';
      const q = room.currentQuestion || findQuestion(room.questions[room.currentQ]);

      // Add who didn't answer
      room.players.forEach(p => {
        if (!room.answers[p.id]) {
          room.answers[p.id] = { playerName: p.name, answerIndex: -1, answerText: 'ما جاوب 😴', botResp: `${p.name} نايم! هزّول يسحب الغطاء عليه 😂` };
        }
      });

      const chatRaw = await redis('GET', `hazal:chat:${roomCode.toUpperCase()}`);
      const chat = chatRaw ? JSON.parse(chatRaw) : [];
      chat.push({ id: Date.now(), type: 'bot', text: REVEAL_INTROS[Math.floor(Math.random() * REVEAL_INTROS.length)], ts: Date.now() });
      Object.entries(room.answers).forEach(([pid, ans], idx) => {
        chat.push({ id: Date.now() + idx + 1, type: 'answer', playerId: pid, playerName: ans.playerName, answer: ans.answerText, questionText: q?.text || '', ts: Date.now() + idx + 1 });
        chat.push({ id: Date.now() + idx + 100, type: 'bot', text: `${ans.playerName}: ${ans.botResp}`, ts: Date.now() + idx + 100 });
      });

      await redis('SET', `hazal:chat:${roomCode.toUpperCase()}`, JSON.stringify(chat.slice(-100)));
      await redis('SET', `hazal:room:${roomCode.toUpperCase()}`, JSON.stringify(room));
      return R(200, { ok: true }, h);
    }

    // ===== NEXT QUESTION =====
    if (action === 'nextQuestion') {
      const { roomCode, playerId } = body;
      const raw = await redis('GET', `hazal:room:${roomCode.toUpperCase()}`);
      if (!raw) return R(404, { error: 'الغرفة غير موجودة' }, h);
      const room = JSON.parse(raw);
      if (room.host !== playerId) return R(403, { error: 'فقط المضيف' }, h);

      room.currentQ = (room.currentQ || 0) + 1;
      if (room.currentQ >= room.questions.length || room.currentQ >= 20) {
        room.phase = 'done';
        room.status = 'done';
      } else {
        room.phase = 'question';
        room.answers = {};
        // Show breathing every 7
        if (room.currentQ % 7 === 0 && room.mode === 'adults') {
          room.phase = 'breathing';
        }
        const q = findQuestion(room.questions[room.currentQ]);
        room.currentQuestion = q;
        // Announce next question in chat
        const chatRaw = await redis('GET', `hazal:chat:${roomCode.toUpperCase()}`);
        const chat = chatRaw ? JSON.parse(chatRaw) : [];
        chat.push({ id: Date.now(), type: 'bot', text: HAZZOUL_INTROS[Math.floor(Math.random() * HAZZOUL_INTROS.length)], ts: Date.now() });
        await redis('SET', `hazal:chat:${roomCode.toUpperCase()}`, JSON.stringify(chat.slice(-100)));
      }

      await redis('SET', `hazal:room:${roomCode.toUpperCase()}`, JSON.stringify(room));
      return R(200, { ok: true, phase: room.phase, currentQ: room.currentQ }, h);
    }

    // ===== DONE BREATHING =====
    if (action === 'doneBreathing') {
      const { roomCode, playerId } = body;
      const raw = await redis('GET', `hazal:room:${roomCode.toUpperCase()}`);
      if (!raw) return R(404, { error: 'الغرفة غير موجودة' }, h);
      const room = JSON.parse(raw);
      if (room.host !== playerId) return R(403, { error: 'فقط المضيف' }, h);
      room.phase = 'question';
      room.answers = {};
      await redis('SET', `hazal:room:${roomCode.toUpperCase()}`, JSON.stringify(room));
      return R(200, { ok: true }, h);
    }

    // ===== GET CHAT =====
    if (action === 'getChat') {
      const { roomCode, since } = body;
      const chatRaw = await redis('GET', `hazal:chat:${roomCode.toUpperCase()}`);
      const chat = chatRaw ? JSON.parse(chatRaw) : [];
      return R(200, { messages: since ? chat.filter(m => m.ts > since) : chat }, h);
    }

    // ===== SEND CHAT =====
    if (action === 'sendChat') {
      const { roomCode, playerId, playerName, message } = body;
      const chatRaw = await redis('GET', `hazal:chat:${roomCode.toUpperCase()}`);
      const chat = chatRaw ? JSON.parse(chatRaw) : [];
      chat.push({ id: Date.now(), type: 'user', playerId, playerName, text: message, ts: Date.now() });
      // هزّول يرد على كل رسالة - دايماً 100%
      const m = message.toLowerCase();
      let botReply;
      if (m.includes('هه') || m.includes('😂') || m.includes('🤣') || m.includes('ههه') || m.includes('haha')) {
        botReply = ['هزّول يبكي من الضحك معكم 😂💀', 'هههههه هزّول ما يصدق! 😂', 'هزّول يطلب إيقاف مؤقت - يضحك بقوة 😂', 'هذا المحتوى لا يُقدّر بثمن! 🏆'][Math.floor(Math.random()*4)];
      } else if (m.includes('هزول') || m.includes('هزّول') || m.includes('بوت')) {
        botReply = ['هزّول هنا! في الخدمة دايماً 🤖😂', 'هزّول يقول: ناديتني؟ 👀', 'هزّول حاضر يا باشا! 🫡', 'هزّول يسمع كل شي حتى لو ما تناديه 👁️😂'][Math.floor(Math.random()*4)];
      } else if (m.includes('؟') || m.includes('?') || m.includes('ليش') || m.includes('وين') || m.includes('كيف') || m.includes('شو') || m.includes('ايش')) {
        botReply = ['هزّول ما عنده جواب... بس عنده ضحكة 😂', 'هزّول يسأل نفس السؤال ويتعجب 🤔😂', 'سؤال وجيه! هزّول يحيل للجلسة القادمة 😂', 'هزّول يقول: الإجابة ستُكشف في الكشف الجماعي 😈'][Math.floor(Math.random()*4)];
      } else if (m.includes('صح') || m.includes('نعم') || m.includes('أيوه') || m.includes('موافق') || m.includes('زين')) {
        botReply = ['هزّول يوافق بشدة ويضرب كف! 👋😂', 'صح صح صح! هزّول مقتنع ١٠٠٪ 😂', 'هزّول يضغط لايك على هذا الكلام 👍🤖', 'هزّول يقول: أخيراً كلام يُنصت له! 😄'][Math.floor(Math.random()*4)];
      } else if (m.includes('لا') || m.includes('مو') || m.includes('ما') || m.includes('رفض')) {
        botReply = ['هزّول يرفض الرفض! 😂', 'هزّول يقول: لا؟! شجاع! 😂', 'هزّول: الرفض موقف - محترم ومضحك 😄', 'هزّول يسأل: متأكد؟ 👀😂'][Math.floor(Math.random()*4)];
      } else {
        const defaults = HAZZOUL_CHAT.concat([
          `هزّول يرد على ${playerName}: كلامك يستاهل تسجيل صوتي 🎙️😂`,
          'هزّول يقول: هذا الكلام يحتاج تحليل 🤔😂',
          `${playerName} قال شي وهزّول تأثر! 🤖💛`,
          'هزّول يوثق هذه اللحظة للأجيال القادمة 📋😂',
        ]);
        botReply = defaults[Math.floor(Math.random()*defaults.length)];
      }
      chat.push({ id: Date.now() + 1, type: 'bot', text: botReply, ts: Date.now() + 1 });
      await redis('SET', `hazal:chat:${roomCode.toUpperCase()}`, JSON.stringify(chat.slice(-100)));
      return R(200, { ok: true }, h);
    }

    return R(400, { error: 'إجراء غير معروف' }, h);

  } catch (err) {
    console.error('Hazal API Error:', err);
    return R(500, { error: 'خطأ في الخادم: ' + err.message }, {
      'Access-Control-Allow-Origin': '*',
      'Content-Type': 'application/json'
    });
  }
};

function R(s, b, h) { return { statusCode: s, headers: h, body: JSON.stringify(b) }; }
